var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니, 대표님! 해치웠어요!","JPN":"お姉ちゃん、代表！　やっつけました！","ENG":"Rita! Boss! We did it! Finally, we made it!","TWN":"姊姊、BOSS！我解決掉囉！"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"동서고금 그런 말은 금기입니다, 대시.","JPN":"古今東西、その言葉は禁忌です。ダッシュ。","ENG":"Dash, that phrase is forbidden across all ages and countries.","TWN":"黛西，不是每件事都要親力親為。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"가만히 있으면 반이라도 간다는 걸 명심하시길.","JPN":"藪をつついて蛇を出すということ、肝に銘じてください。","ENG":"Remember that silence is also a viable option.","TWN":"我希望你記住，你不出手自然有其他人會出手。"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그래도 해치웠으니 이제 집에 돌아갈 수 있는 거겠죠?","JPN":"でもやっつけましたから、もうお家に帰れるんでしょう？","ENG":"But we defeated it, so we can go home now, right?","TWN":"反正都解決掉了，現在可以回家了吧？"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"다들 빨리…","JPN":"みんな、早く……","ENG":"Let's get out of–","TWN":"大家快…"},"stage":{"bg":"MIND","bgm":"BATTLE_NORMAL_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":" 어?","JPN":" あ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"꼬맹이?","JPN":"ガキ？","ENG":"Kid?","TWN":"小鬼？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"진정하십시오. 환상을 극복해낸 순으로 돌아갈 뿐입니다.","JPN":"落ち着いてください。幻を克服した順で帰るだけです。","ENG":"Calm down. We are returning in order of overcoming the illusions.","TWN":"放心，現在是按照克服幻想的順序回去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"연약한 리타와는 달리 대시는 가장 먼저 환상을 극복해냈으니 말입니다.","JPN":"軟弱なリタとは違って、ダッシュは真っ先に幻を乗り切ったのですから。","ENG":"Unlike frail Rita, Dash was the first to overcome the illusion.","TWN":"意思就是 黛西和軟弱的你不同，她是最先克服幻想的那一個。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"바로 돌아가지 않는 걸 보니, 너도 꽤나 고생했나 봐?","JPN":"すぐ帰らないのを見ると、お前も結構苦労したようだな。","ENG":"Seeing how you're not returning yet, you must've struggled as well, eh?","TWN":"那你和我一起留在這裡，就表示你也蠻軟弱的嘛？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"진공관 맙소사. 망나니처럼 날뛰다 남의 손이나 빌린 리타가 할 말은 아니군요.","JPN":"オーマイ真空管。暴れまくった挙句に人に助けられたリタの言うセリフではありませんね。","ENG":"Oh my diodes. I do not want to hear that from someone who got help after acting all tough.","TWN":"我的真空管，竟然向收留你這個女流氓的人說出這種話。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저희는 기다리기만 하면 그만입니다.","JPN":"私たちはただ待つだけでいいのです。","ENG":"All we have to do now is wait.","TWN":"我們只需要等待就好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기까지 와서 술입니까?","JPN":"ここまで来てお酒ですか？","ENG":"You are going to drink, all the way here?","TWN":"這種時候還要喝酒？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"환상이면 안 취한다는 소리잖아? 꼬맹이한테 잔소리 들을 일도 없으니, 마음껏 마셔야지.","JPN":"幻なら、酔わないってことだろう？　ガキにごちゃごちゃ言われることもないし、いっぱい飲まないと。","ENG":"If this is all fake, then I won't get drunk, right? Plus, the kid's not here to nag me, so I'd better drink to my heart's content.","TWN":"在幻想中應該不會醉吧？又不用聽小鬼嘮叨，當然要喝個過癮。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"탄소 생명체 아니랄까 봐 조금의 절제력도 없군요. 이래서 휴먼들이란.","JPN":"炭素生命体らしく、少しの自制心もありませんね。これだからヒューマンは。","ENG":"What a carbon-based lifeform thing to say. You seem to have no self-control. This is why humans are so helpless.","TWN":"是怕人家不知道你是碳基生物嗎？一點自制力都沒有，果然是人類。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"받아.","JPN":"ほれ。","ENG":"Here.","TWN":"拿去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"기계한테 술이라니. 리타는 기계보호협회의 철퇴가 두렵지 않나 보군요.","JPN":"機械にお酒とは。リタは機械保護協会の鉄槌が怖くないようです。","ENG":"Giving alcohol to a machine? I see you are not afraid of the consequences the Machine Protection Association will penalize you with, Rita.","TWN":"竟然給機械喝酒？我看你根本不畏懼機械保護協會的鐵鎚。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"진공관께서도 노하셨습니다. 어서 빨리 기도하십시오.","JPN":"真空管様もご立腹です。早く祈りを捧げてください。","ENG":"You have angered the diodes. Quickly, you must now pray.","TWN":"真空管現在非常憤怒，我勸你趕快祈禱。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"윤활유야. 혹시 몰라 시도해봤는데 이런 것도 되더라고.","JPN":"潤滑油だ。もしかしてと試して見たがら、こんなこともできた。","ENG":"It's lubricants. I just tried it to see if it works, and it does.","TWN":"是潤滑油，想說試試看，沒想到也還可以。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이달의 우수사원에 리타의 이름을 올리도록 하겠습니다.","JPN":"今月の優秀社員にリタの名前を上げましょう。","ENG":"I shall announce you as employee of the month, Rita.","TWN":"這個月的優秀員工就決定是麗塔了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"필요없어. 상여금도 안 나오는 그딴 건.","JPN":"要らない。ボーナスもくれないんだろう？","ENG":"I don't need it. It doesn't even come with a bonus.","TWN":"不必了，又沒有獎金，要那個虛名幹嘛。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"뭐, 오래 일한 것 치고는 너랑은 마셔본 적이 없으니까.","JPN":"まあ、長く働いた割には、お前とは飲んだことがなかったからな。","ENG":"And for as long as I've worked here, you and I have never had a drink together.","TWN":"只想說我們一起共事這麼久，似乎還沒和你一起喝一杯過。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"가끔씩은 이런 것도 괜찮겠지.","JPN":"たまにはこんなのもいいだろう。","ENG":"It's okay to do something like this every now and then.","TWN":"偶爾這樣也不錯吧？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"와인잔에 따라 마시는 윤활유도 나쁘지 않군요. 단체 회식 때 종종 써먹겠습니다.","JPN":"ワイングラスに注いで飲む潤滑油も悪くありません。飲み会でたまに使うとします。","ENG":"Drinking lubricant from a wine glass is not that bad. I should use this more in company dinners.","TWN":"用紅酒杯喝潤滑油也蠻不錯的，聚餐時也可以試試。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"단체 회식은 개뿔. 지금껏 한 번도 한 적 없으면서.","JPN":"飲み会って。今まで一度もやったことないくせに。","ENG":"Company dinners? As if. You've never done one this entire time.","TWN":"聚你個鬼，我們根本從來沒有聚餐過。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"다 같이 밥 먹으면 그게 회식이지, 뭐가 회식입니까? 리타는 바라는 게 참 많군요.","JPN":"みんな一緒でご飯を食べることも飲み会です。リタは欲張りですね。","ENG":"Eating together is always a company dinner, what else would it be? You seem to have a lot of wants and needs, Rita.","TWN":"一起吃飯不算聚餐，那什麼才是聚餐？麗塔的要求真的很多。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"…바라는 게 많다라.","JPN":"……欲張りか。","ENG":"...A lot of wants and needs, eh?","TWN":"…要求很多嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"그래. 어쩌면 그럴지도.","JPN":"ああ。もしかしたらそうなのかも。","ENG":"Yeah. I guess so.","TWN":"或許吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"뭡니까. 알코올도 없는 술에 취한 겁니까?","JPN":"何ですか。アルコールもないお酒に酔いましたか？","ENG":"What is it? Are you drunk without alcohol?","TWN":"你怎麼回事？喝無酒精的酒也能喝醉嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"유감이군요. 고성능을 자랑하는 제게도 공감 능력 모듈은 설치되어 있지 않습니다.","JPN":"残念です。高性能を誇る私にも、共感能力モジュールは設置されていません。","ENG":"I am sorry, but even a high-performing model like me does not have an empathy module installed.","TWN":"不是我要老王賣瓜，我的性能確實很卓越，但遺憾的是，並沒有內建同理模組。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"바라지도 않아. 술자리라는 건 결국 제 할 말만 하는 형식상의 자리에 불과하니까.","JPN":"望んでもない。飲み会って結局自分の話したいことばかり話す、儀礼的な場に過ぎない。","ENG":"I don't want empathy. A dinner with drinks is just a place to say whatever is on one's mind.","TWN":"我不期待你能理解，畢竟這種喝酒的場合，不過就是在各說各話而已。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"쌓인 불만이라던가. 뭐, 그런 걸 털어놓는 거지. 돼먹지 못한 알코올에 기대서.","JPN":"溜まっていた不満とか。ま、そんなことをぶちまけるんだ。くだらないアルコールに頼って。","ENG":"Such as accumulated dissatisfaction or something, while relying on good ol' liquid courage.","TWN":"趁著幾杯黃湯下肚，將累積的不滿全都宣洩出來。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리타가 만들어낸 환상 중에는 저와 대시의 모습도 있더군요.","JPN":"リタが作り出した幻の中には、私とダッシュの姿もいました。","ENG":"Of the illusions you made, Rita, there were ones that looked like me and Dash.","TWN":"沒想到我和黛西也存在在麗塔創造的幻想中。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"리타는 저희 회사에 온 걸 후회하십니까?","JPN":"リタはこの会社に来たことを後悔していますか？","ENG":"Do you regret joining my company?","TWN":"你是後悔進到我們公司嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"확실히. 변변찮은 풀죽이 주식인 데다 즉흥적으로 돌아가는 구석이 있지.","JPN":"確かに。お粗末なお粥が主食で、気まぐれで流れてるところがある。","ENG":"Well. There certainly is room for improvement since all we eat is grass porridge and we take on jobs spontaneously.","TWN":"確實是，伙食是難吃的野菜粥，還有一堆臨時狀況。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"그래도 너희랑 지내는 건 썩 나쁘지 않아.","JPN":"それでも、お前たちと過ごすのはまあ、悪くない。","ENG":"But being with you two isn't that bad.","TWN":"不過，和你們一起共事還蠻不錯的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이런 말 하기 뭐하지만…….","JPN":"こんなことを言うのもあれだけど……","ENG":"I don't know how it's going to sound…","TWN":"說這種話有點尷尬……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"다른 건 몰라도, 네가 직장상사로서는 썩 나쁘지 않거든.","JPN":"ともかく、お前は職場の上司としては結構悪くないんだ。","ENG":"But at least, you're not a bad boss.","TWN":"其他我不確定，但你的確是個不錯的上司。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"하.","JPN":"は。","ENG":"Hah.","TWN":"哈。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"이야기 도중에 사라져버리다니.","JPN":"話の途中に消えるとは。","ENG":"She just disappeared while I was talking.","TWN":"話說到一半就消失，"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_CONTEST_NULL_NULL","text":{"KOREA":"정말이지. 술친구로서 실격이구만.","JPN":"まったく。飲み友達として失格だな。","ENG":"Ugh, guess she won't make a good drinking buddy.","TWN":"不是個合格的酒伴呢。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_CONTEST_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};